class Solution {
    public int[] numsSameConsecDiff(int n, int k) {
        List<Integer> res = new ArrayList<>();
        if (n == 1) {
            for (int i = 0; i <= 9; i++) {
                res.add(i);
            }
            return res.stream().mapToInt(i -> i).toArray();
        }
        for (int i = 1; i <= 9; i++) {
            dfs(res, i, i, n - 1, k);
        }
        return res.stream().mapToInt(i -> i).toArray();
    }

    private void dfs(List<Integer> res, int cur, int prev, int n, int k) {
        if (n == 0) {
            res.add(cur);
            return;
        }
        for (int i = 0; i <= 9; i++) {
            if (Math.abs(i - prev) == k) {
                dfs(res, cur * 10 + i, i, n - 1, k);
            }
        }
    }
}
